class Solution {
    public int leastInterval(char[] tasks, int n) {
        int[] freq = new int[26];
        for (char t : tasks) freq[t - 'A']++;
        PriorityQueue<Integer> heap = new PriorityQueue<>(Comparator.reverseOrder());
        for (int f : freq) if (f > 0) heap.offer(f);
        int time = 0;
        while (!heap.isEmpty()) {
            List<Integer> temp = new ArrayList<>();
            int interval = 0;
            for (int i = 0; i <= n; i++) {
                if (!heap.isEmpty()) {
                    temp.add(heap.poll() - 1);
                    interval++;
                }
            }
            for (int rem : temp) if (rem > 0) heap.offer(rem);
            time += heap.isEmpty() ? interval : n + 1;
        }
        return time;
    }
}
